/**
 * @summary Aggregated verdict accuracy and miss-theme analysis across closed deals
 */
export const GetDoctrineSummaryResponse = zod.object({
  accuracyBySector: zod.array(
    zod.object({
      sector: zod.string(),
      correct: zod.number(),
      partiallyCorrect: zod.number(),
      wrong: zod.number(),
      total: zod.number(),
    }),
  ),
  missThemes: zod.array(
    zod.object({
      theme: zod.string(),
      count: zod.number(),
    }),
  ),
  winLossBySector: zod.array(
    zod.object({
      sector: zod.string(),
      wins: zod.number(),
      losses: zod.number(),
      total: zod.number(),
    }),
  ),
  recentClosures: zod.array(
    zod.object({
      id: zod.number(),
      targetCode: zod.string(),
      projectName: zod.string(),
      sector: zod.string().nullish(),
      currentStage: zod.string(),
      closeReasonCode: zod.string().nullish(),
      phase1VerdictAccuracy: zod.string().nullish(),
      phase1VerdictNote: zod.string().nullish(),
      closeMissTheme: zod.string().nullish(),
      updatedAt: zod.string().nullish(),
    }),
  ),
  accuracyByQuarter: zod
    .array(
      zod.object({
        period: zod
          .string()
          .describe('Human-readable label e.g. \"Q2 2025\" or \"Jun 2025\"'),
        periodStart: zod
          .string()
          .describe(
            "ISO 8601 date of the first day of the period (for sorting\/filtering)",
          ),
        total: zod.number(),
        correct: zod.number(),
        partiallyCorrect: zod.number(),
        wrong: zod.number(),
        accuracyPct: zod
          .number()
          .describe("Percentage of correct verdicts (0–100)"),
      }),
    )
    .describe("Phase 1 accuracy % bucketed by quarter (chronological)"),
  accuracyByMonth: zod
    .array(
      zod.object({
        period: zod
          .string()
          .describe('Human-readable label e.g. \"Q2 2025\" or \"Jun 2025\"'),
        periodStart: zod
          .string()
          .describe(
            "ISO 8601 date of the first day of the period (for sorting\/filtering)",
          ),
        total: zod.number(),
        correct: zod.number(),
        partiallyCorrect: zod.number(),
        wrong: zod.number(),
        accuracyPct: zod
          .number()
          .describe("Percentage of correct verdicts (0–100)"),
      }),
    )
    .describe("Phase 1 accuracy % bucketed by calendar month (chronological)"),
});

